-- ── Compliance Tables ────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS compliance_regulations (
  id               uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  code             text UNIQUE NOT NULL,
  short_name       text NOT NULL,
  name             text NOT NULL,
  regions          text[] NOT NULL,
  industries       text[],            -- NULL = all industries
  jurisdiction     text NOT NULL,
  authority        text,
  type             text NOT NULL,     -- 'privacy' | 'security' | 'sector'
  summary          text NOT NULL,
  max_fine         text,
  effective_date   date,
  last_verified_at timestamptz DEFAULT now(),
  active           boolean DEFAULT true,
  created_at       timestamptz DEFAULT now()
);

CREATE TABLE IF NOT EXISTS compliance_requirements (
  id            uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  regulation_id uuid NOT NULL REFERENCES compliance_regulations(id) ON DELETE CASCADE,
  article       text NOT NULL,
  title         text NOT NULL,
  description   text NOT NULL,
  dlp_relevance text NOT NULL,
  fine          text,
  severity      text NOT NULL,        -- 'critical' | 'high' | 'medium'
  dlp_controls  text[],
  created_at    timestamptz DEFAULT now()
);

CREATE TABLE IF NOT EXISTS compliance_verification_log (
  id            uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  regulation_id uuid NOT NULL REFERENCES compliance_regulations(id),
  org_id        uuid NOT NULL,
  verified_by   uuid,
  verified_at   timestamptz DEFAULT now(),
  changed       boolean DEFAULT false,
  changes       jsonb,
  notes         text
);

CREATE TABLE IF NOT EXISTS compliance_assessments (
  id            uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  org_id        uuid NOT NULL,
  control_key   text NOT NULL,
  regulation_id uuid NOT NULL REFERENCES compliance_regulations(id),
  status        text NOT NULL DEFAULT 'not_assessed',
  notes         text,
  updated_at    timestamptz DEFAULT now(),
  UNIQUE(org_id, control_key, regulation_id)
);

-- ── RLS ──────────────────────────────────────────────────────────────────────

ALTER TABLE compliance_regulations      ENABLE ROW LEVEL SECURITY;
ALTER TABLE compliance_requirements     ENABLE ROW LEVEL SECURITY;
ALTER TABLE compliance_verification_log ENABLE ROW LEVEL SECURITY;
ALTER TABLE compliance_assessments      ENABLE ROW LEVEL SECURITY;

-- Regulations & requirements: public read (no org isolation needed — shared reference data)
CREATE POLICY "public_read" ON compliance_regulations
  FOR SELECT USING (true);

CREATE POLICY "public_read" ON compliance_requirements
  FOR SELECT USING (true);

-- Verification log & assessments: org-scoped
CREATE POLICY "org_isolation" ON compliance_verification_log
  USING (org_id = (auth.jwt() ->> 'org_id')::uuid);

CREATE POLICY "org_isolation" ON compliance_assessments
  USING (org_id = (auth.jwt() ->> 'org_id')::uuid);

