INSERT INTO compliance_requirements (regulation_id, article, title, description, dlp_relevance, fine, severity, dlp_controls)
SELECT r.id, req.article, req.title, req.description, req.dlp_relevance, req.fine, req.severity, req.dlp_controls
FROM compliance_regulations r
JOIN (VALUES
  -- GDPR
  ('gdpr','Article 5(1)(f)','Integrity and Confidentiality','Personal data must be processed securely to protect against unauthorised or unlawful processing and against accidental loss, destruction or damage.','DLP directly enforces this principle by preventing unauthorised data exfiltration across all channels (web, email, endpoint, SaaS).','€20M or 4% of global annual turnover','critical',ARRAY['data_classification','dlp_web','dlp_email','dlp_endpoint','dlp_saas']),
  ('gdpr','Article 25','Data Protection by Design and by Default','Controllers must implement appropriate technical and organisational measures to integrate data protection principles into processing activities by design and by default.','DLP policies must be built into systems from the start — not bolted on. Data classification and access controls are the foundation of privacy-by-design.','€10M or 2% of global annual turnover','high',ARRAY['data_classification','access_controls','dlp_saas']),
  ('gdpr','Article 32','Security of Processing','Controllers and processors must implement appropriate technical and organisational measures including encryption, pseudonymisation, and ongoing confidentiality.','The core technical obligation. DLP tools are a primary mechanism for meeting Art. 32 — covering encryption in transit, access controls, and preventing unauthorised disclosure.','€10M or 2% of global annual turnover','critical',ARRAY['dlp_web','dlp_email','dlp_endpoint','dlp_saas','genai_controls','encryption_transit','access_controls']),
  ('gdpr','Article 33','Notification of Personal Data Breach (72-hour)','The controller must notify the relevant supervisory authority within 72 hours of becoming aware of a personal data breach.','DLP alerting and audit logging are the detection mechanism. Without them, organisations cannot identify breaches in time to meet the 72-hour notification window.','€10M or 2% of global annual turnover','critical',ARRAY['audit_logging','breach_detection']),
  ('gdpr','Article 34','Communication of Breach to Data Subject','When a breach is likely to result in high risk to individuals, the controller must communicate the breach without undue delay.','DLP breach detection identifies the scope of a breach (which data, which individuals), enabling accurate communication to affected data subjects.','€20M or 4% of global annual turnover','high',ARRAY['breach_detection','audit_logging']),

  -- UK GDPR
  ('uk_gdpr','Article 5(1)(f)','Integrity and Confidentiality','Personal data must be processed securely to protect against unauthorised processing and accidental loss or damage.','Same as EU GDPR — DLP enforces the integrity and confidentiality principle across all data channels.','£17.5M or 4% of global annual turnover','critical',ARRAY['data_classification','dlp_web','dlp_email','dlp_endpoint','dlp_saas']),
  ('uk_gdpr','Article 32','Security of Processing','Appropriate technical and organisational measures must be implemented to ensure data security, including encryption and ongoing confidentiality.','DLP is a primary technical measure for meeting the security of processing obligation under UK GDPR.','£10M or 2% of global annual turnover','critical',ARRAY['dlp_web','dlp_email','encryption_transit','access_controls','genai_controls']),
  ('uk_gdpr','Article 33','Breach Notification (72-hour)','Notify the ICO within 72 hours of becoming aware of a personal data breach.','DLP audit logs provide the evidence trail needed to identify breach timing and scope for ICO notification.','£17.5M or 4% of global annual turnover','critical',ARRAY['audit_logging','breach_detection']),
  ('uk_gdpr','ICO Guidelines','Accountability and Governance','Organisations must demonstrate compliance and maintain records of processing activities.','DLP audit trails and classification policies are key evidence of accountability to the ICO.','£8.75M or 2% of global annual turnover','high',ARRAY['data_classification','audit_logging']),

  -- NIS2
  ('nis2','Article 21(2)(a)','Risk Analysis and Security Policies','Risk analysis and information system security policies covering all aspects of cybersecurity risk management.','DLP gap assessments feed directly into the risk analysis required under NIS2 for data exfiltration risks.','€10M or 2% of global annual turnover','high',ARRAY['data_classification','audit_logging']),
  ('nis2','Article 21(2)(b)','Incident Handling','Entities must have policies and procedures for handling cybersecurity incidents, including detection, containment, and recovery.','DLP breach detection and audit logging are core to incident detection and response capabilities required by NIS2.','€10M or 2% of global annual turnover','critical',ARRAY['breach_detection','audit_logging']),
  ('nis2','Article 21(2)(d)','Supply Chain Security','Security in supply chain relationships, including security aspects concerning relationships with direct suppliers or service providers.','DLP controls on SaaS applications and data sharing with third parties directly address supply chain data security.','€10M or 2% of global annual turnover','high',ARRAY['dlp_saas','data_classification','access_controls']),
  ('nis2','Article 21(2)(h)','Access Control and Human Resources Security','Access control policies including need-to-know, multi-factor authentication, and human resources security measures.','DLP access controls and data classification enforce need-to-know principles across all data channels.','€10M or 2% of global annual turnover','high',ARRAY['access_controls','data_classification','dlp_endpoint']),

  -- DORA
  ('dora','Article 8','ICT Asset Management','Financial entities must identify, classify and document all ICT assets, including those that support critical or important functions.','Data classification is fundamental to ICT asset management — knowing what data exists and where it flows.','Supervisory measures','high',ARRAY['data_classification']),
  ('dora','Article 9','Protection and Prevention','Financial entities must put in place ICT security policies to ensure the protection of ICT assets from cyberattacks.','DLP tools are a primary protection measure for preventing data exfiltration and insider threats within financial entities.','Supervisory measures and periodic penalty payments','critical',ARRAY['dlp_web','dlp_email','dlp_endpoint','dlp_saas','access_controls']),
  ('dora','Article 10','Detection','Financial entities must have mechanisms for promptly detecting anomalous activities including ICT-related incidents.','DLP anomaly detection and audit logging are core detection mechanisms for data-related ICT incidents.','Supervisory measures','high',ARRAY['audit_logging','breach_detection']),
  ('dora','Article 17','ICT-Related Incident Management','Financial entities must establish and implement ICT-related incident management processes for detecting, managing, and notifying incidents.','DLP breach detection and audit logging are the first line of incident detection for data-related breaches.','Supervisory measures','critical',ARRAY['breach_detection','audit_logging']),

  -- DPDP Act
  ('dpdp','Section 8(4)','Security Safeguards','Data fiduciaries must implement appropriate technical and organisational measures to protect personal data.','DLP is a core technical safeguard under DPDP — preventing unauthorised access and exfiltration of personal data.','₹250 Crore per violation','critical',ARRAY['data_classification','dlp_web','dlp_email','dlp_endpoint','encryption_transit','access_controls']),
  ('dpdp','Section 8(6)','Personal Data Breach Notification','Data fiduciaries must notify the Data Protection Board and affected data principals in the event of a personal data breach.','DLP breach detection and audit logging enable organisations to identify breaches quickly for Board notification.','₹200 Crore per violation','critical',ARRAY['breach_detection','audit_logging']),
  ('dpdp','Section 6','Purpose Limitation and Data Minimisation','Personal data must be processed only for the specific lawful purpose and not retained beyond the necessary period.','DLP classification policies enforce purpose limitation by controlling where and how different categories of personal data can flow.','₹150 Crore per violation','high',ARRAY['data_classification','access_controls','dlp_saas']),
  ('dpdp','Section 9','Processing of Children''s Personal Data','Data fiduciaries must obtain verifiable parental consent before processing personal data of children (under 18).','DLP content inspection can detect and block the unauthorised processing or transfer of data tagged as belonging to minors.','₹200 Crore per violation','high',ARRAY['data_classification','dlp_web','dlp_saas']),

  -- RBI CSF
  ('rbi_csf','Annex I — Controls','Data-at-Rest and Data-in-Transit Protection','Banks must implement encryption and access controls for sensitive customer data both at rest and in transit.','DLP enforces encryption-in-transit policies and prevents unencrypted sensitive banking data from leaving the organisation.','Regulatory penalty under BR Act','critical',ARRAY['encryption_transit','dlp_email','dlp_web','access_controls']),
  ('rbi_csf','Section 6 — Incident Response','Cyber Incident Reporting (6-hour rule)','Banks must report cybersecurity incidents to RBI within 2–6 hours of detection.','DLP alerting provides immediate notification of data exfiltration events, enabling banks to meet the RBI''s strict 6-hour reporting window.','Regulatory penalty under BR Act','critical',ARRAY['breach_detection','audit_logging']),
  ('rbi_csf','Section 4 — Data Classification','Data Classification and Handling','Banks must classify data based on sensitivity and implement controls commensurate with the classification level.','Data classification is the foundation of the RBI framework — all other DLP controls flow from proper classification.','Regulatory penalty','high',ARRAY['data_classification','dlp_endpoint']),

  -- SEBI CSCRF
  ('sebi_cscrf','Section 3 — Controls','Data Leakage Prevention','SEBI-regulated entities must implement DLP solutions to prevent unauthorised disclosure of confidential securities market data.','SEBI explicitly requires DLP implementation as a mandatory control for protecting market-sensitive information.','Regulatory sanctions','critical',ARRAY['dlp_web','dlp_email','dlp_endpoint','dlp_saas','data_classification']),
  ('sebi_cscrf','Section 4 — Incident Management','Incident Detection and Reporting','Entities must implement mechanisms to detect, respond to, and report cybersecurity incidents to SEBI.','DLP audit logging and breach detection provide the detection layer required for SEBI incident management.','Regulatory sanctions','high',ARRAY['audit_logging','breach_detection']),
  ('sebi_cscrf','Section 2 — Governance','Data Classification and Access Control','Regulated entities must classify data based on sensitivity, implement access controls, and maintain audit trails.','Data classification and access controls are foundational to the SEBI framework — particularly for preventing insider trading data leaks.','Regulatory sanctions','high',ARRAY['data_classification','access_controls','audit_logging']),

  -- HIPAA
  ('hipaa','§164.308(a)(1)','Security Management Process','Covered entities must implement policies and procedures to prevent, detect, contain, and correct security violations, including risk analysis.','DLP is a core risk management control under HIPAA — it prevents unauthorised disclosure of PHI and provides evidence for risk analysis.','$100,000 to $1.9M per violation category','critical',ARRAY['data_classification','breach_detection','audit_logging']),
  ('hipaa','§164.312(a)(1)','Access Control','Implement technical policies allowing ePHI access only to authorised persons or software programs.','DLP access controls enforce who can access, copy, or transmit ePHI, preventing both insider threats and accidental disclosure.','$100,000 to $1.9M per violation category','critical',ARRAY['access_controls','dlp_endpoint','dlp_saas']),
  ('hipaa','§164.312(b)','Audit Controls','Implement hardware, software, and/or procedural mechanisms that record and examine activity in systems containing ePHI.','DLP audit logging is a direct implementation of the HIPAA audit controls requirement, providing full activity trails for ePHI.','$100,000 to $1.9M per violation category','critical',ARRAY['audit_logging']),
  ('hipaa','§164.312(c)(1)','Integrity Controls','Implement policies and procedures to protect ePHI from improper alteration or destruction.','DLP prevents unauthorised modification or deletion of ePHI by controlling who can access and manipulate PHI files.','$100,000 to $1.9M per violation category','high',ARRAY['data_classification','access_controls','dlp_endpoint']),
  ('hipaa','§164.312(e)(1)','Transmission Security','Implement technical security measures to guard against unauthorised access to ePHI transmitted over networks.','DLP enforces encryption in transit and blocks unencrypted PHI from being transmitted via email, web, or other channels.','$100,000 to $1.9M per violation category','critical',ARRAY['encryption_transit','dlp_email','dlp_web']),

  -- GLBA
  ('glba','16 CFR §314.4(c)','Access Controls','Financial institutions must implement multi-factor authentication, access limitations, and encryption of customer data.','DLP enforces the access control and encryption requirements for customer financial data across all channels.','$100,000 per violation','critical',ARRAY['access_controls','encryption_transit','dlp_endpoint']),
  ('glba','16 CFR §314.4(d)','Encryption of Customer Information','Customer information in transit over external networks or at rest must be encrypted using current cryptographic standards.','DLP enforces encryption-in-transit policies and blocks unencrypted customer financial data from leaving the organisation.','$100,000 per violation','critical',ARRAY['encryption_transit','dlp_email','dlp_web']),
  ('glba','16 CFR §314.4(f)','Monitor and Test','Financial institutions must regularly monitor and test the effectiveness of security controls.','DLP testing (via Control Validator) and audit trail review are the monitoring mechanisms required under GLBA.','$100,000 per violation','high',ARRAY['audit_logging','breach_detection']),
  ('glba','16 CFR §314.4(h)','Incident Response Plan','Institutions must establish a written incident response plan to address unauthorised access to or use of customer information.','DLP breach detection is the triggering mechanism for the GLBA incident response plan.','$100,000 per violation','high',ARRAY['breach_detection','audit_logging']),

  -- CCPA/CPRA
  ('ccpa','§1798.81.5','Reasonable Security Measures','Businesses must implement and maintain reasonable security procedures and practices appropriate to the nature of the personal information they collect.','DLP is a cornerstone of "reasonable security" for businesses holding Californian consumer data — covering web, email, endpoint, and SaaS channels.','$100–$750 per consumer per incident','critical',ARRAY['data_classification','dlp_web','dlp_email','dlp_endpoint','encryption_transit']),
  ('ccpa','§1798.150','Private Right of Action for Data Breaches','Consumers have a private right of action against businesses for data breaches resulting from failure to implement reasonable security measures.','DLP prevents the data breaches that trigger CCPA/CPRA private litigation — each blocked exfiltration is a prevented lawsuit.','$100–$750 per consumer per incident or actual damages','critical',ARRAY['breach_detection','audit_logging','dlp_web','dlp_email']),
  ('ccpa','CPRA §1798.100(d)','Data Minimisation and Purpose Limitation','Businesses must not collect more personal information than reasonably necessary and must not use it for incompatible purposes.','DLP classification policies enforce purpose limitation by controlling data flows and preventing use beyond disclosed purposes.','$2,500–$7,500 per violation','medium',ARRAY['data_classification','dlp_saas','access_controls']),

  -- CMMC
  ('cmmc','AC.L2-3.1.3','CUI Flow Control','Control the flow of Controlled Unclassified Information (CUI) in accordance with approved authorisations.','DLP directly implements CUI flow control — the primary control for preventing unauthorised CUI disclosure across all channels.','Loss of contract eligibility','critical',ARRAY['data_classification','dlp_web','dlp_email','dlp_endpoint','dlp_saas']),
  ('cmmc','AU.L2-3.3.1','Audit Logging','Create and retain system audit logs and records to enable monitoring, analysis, investigation, and reporting of unlawful or unauthorised system activity.','DLP audit logging provides the required audit records for all CUI-related activities and potential incidents.','Loss of contract eligibility','critical',ARRAY['audit_logging']),
  ('cmmc','MP.L2-3.8.5','Media Sanitisation and Protection','Control access to media containing CUI and sanitise or destroy media before disposal or reuse.','DLP endpoint controls prevent CUI from being copied to removable media and enforce controls over physical data transfer.','Loss of contract eligibility','high',ARRAY['dlp_endpoint','access_controls']),
  ('cmmc','SC.L2-3.13.16','CUI at Rest','Protect the confidentiality of CUI at rest.','DLP classification and access controls ensure CUI is identified and protected wherever it resides.','Loss of contract eligibility','high',ARRAY['data_classification','encryption_transit','access_controls']),

  -- SOX
  ('sox','Section 404','Management Assessment of Internal Controls','Management must annually assess the effectiveness of internal controls over financial reporting (ICFR).','DLP controls over financial data (access logs, data movement records) are key evidence for SOX Section 404 internal control assessments.','$1M–$5M and up to 20 years imprisonment','critical',ARRAY['data_classification','audit_logging','access_controls']),
  ('sox','Section 802','Records Management and Retention','Prohibits alteration or destruction of financial records. Requires retention of audit work papers for 7 years.','DLP controls prevent unauthorised deletion or modification of financial records and ensure audit trails are preserved.','$1M–$5M and up to 20 years imprisonment','critical',ARRAY['audit_logging','access_controls','breach_detection']),
  ('sox','Section 302','Corporate Responsibility for Financial Reports','CEOs and CFOs must personally certify the accuracy of financial statements and the effectiveness of internal controls.','DLP audit trails provide the evidence executives rely on when certifying the integrity of financial data and internal controls.','$1M–$5M and up to 20 years imprisonment','high',ARRAY['audit_logging','data_classification']),

  -- PCI-DSS
  ('pci_dss','Requirement 3','Protect Stored Account Data','Cardholder data and sensitive authentication data must be identified, classified, and protected wherever stored.','DLP identifies and prevents storage of unprotected cardholder data, enforcing PCI-DSS Requirement 3 across all data stores.','$5,000–$100,000 per month','critical',ARRAY['data_classification','dlp_endpoint','dlp_saas']),
  ('pci_dss','Requirement 4','Protect Cardholder Data in Transit','Strong cryptography must be used to protect cardholder data during transmission over open, public networks.','DLP enforces encryption-in-transit policies and blocks unencrypted cardholder data from being transmitted via email, web, or other channels.','$5,000–$100,000 per month','critical',ARRAY['encryption_transit','dlp_email','dlp_web']),
  ('pci_dss','Requirement 7','Restrict Access to System Components','Access to system components and cardholder data must be restricted to only those individuals whose job requires such access.','DLP access controls enforce need-to-know for cardholder data and prevent unauthorised users from accessing or exporting PCI data.','$5,000–$100,000 per month','critical',ARRAY['access_controls','data_classification']),
  ('pci_dss','Requirement 10','Log and Monitor All Access','All access to system components and cardholder data must be logged and log data reviewed for anomalies or suspicious activity.','DLP audit logging provides the comprehensive activity logs required by PCI-DSS Requirement 10.','$5,000–$100,000 per month','critical',ARRAY['audit_logging','breach_detection']),

  -- PDPA (SG)
  ('pdpa_sg','Section 24 (Protection Obligation)','Protection of Personal Data','Organisations must protect personal data by making reasonable security arrangements to prevent unauthorised access, collection, use, or disclosure.','DLP implements the PDPA''s reasonable security arrangements requirement by preventing unauthorised access and disclosure across all channels.','SGD 1M or 10% of annual turnover','critical',ARRAY['data_classification','dlp_web','dlp_email','dlp_endpoint','encryption_transit']),
  ('pdpa_sg','Section 26D (Breach Notification)','Mandatory Data Breach Notification (3-day)','Organisations must notify the PDPC within 3 calendar days for breaches likely to result in significant harm.','DLP breach detection enables organisations to identify and scope data breaches quickly, meeting the PDPC''s strict 3-day notification window.','SGD 1M or 10% of annual turnover','critical',ARRAY['breach_detection','audit_logging']),
  ('pdpa_sg','Section 25 (Retention Limitation)','Retention and Disposal','Personal data must not be retained longer than necessary and must be properly disposed of when no longer needed.','DLP classification policies support data lifecycle management by identifying and controlling personal data throughout its lifecycle.','SGD 1M or 10% of annual turnover','medium',ARRAY['data_classification']),

  -- PIPL
  ('pipl','Article 51','Personal Information Security Measures','Personal information processors must adopt necessary measures to safeguard personal information security, prevent unauthorised access, disclosure, alteration, and deletion.','DLP controls across web, email, endpoint, and SaaS channels are the primary technical measures for PIPL Article 51 compliance.','¥50M or 5% of annual revenue','critical',ARRAY['data_classification','dlp_web','dlp_email','dlp_endpoint','access_controls']),
  ('pipl','Article 57','Personal Information Breach Notification','Processors must immediately notify the relevant authorities and affected individuals upon discovering a personal information breach.','DLP breach detection enables prompt identification of data breaches, supporting PIPL''s immediate notification requirement.','¥50M or 5% of annual revenue','critical',ARRAY['breach_detection','audit_logging']),
  ('pipl','Article 38','Cross-Border Data Transfer Restrictions','Cross-border transfer of personal information requires CAC security assessment, approved standard contracts, or certification.','DLP controls on web uploads, email, and SaaS applications are essential for enforcing PIPL''s strict cross-border transfer restrictions.','¥50M or 5% of annual revenue','critical',ARRAY['dlp_web','dlp_email','dlp_saas','data_classification']),

  -- APPI
  ('appi','Article 23 / 24','Security Management Measures','Business operators must take necessary and appropriate measures for the secure management of personal information to prevent leakage, loss, or damage.','DLP provides the technical security measures required under APPI for protecting personal information from leakage across all channels.','¥100M corporate fine','critical',ARRAY['data_classification','dlp_web','dlp_email','dlp_endpoint','encryption_transit']),
  ('appi','Article 26','Mandatory Breach Reporting','Businesses must report to the PPC and notify affected individuals when a breach is likely to harm individuals'' rights and interests.','DLP breach detection enables timely identification of data breaches for APPI reporting obligations.','¥100M corporate fine','high',ARRAY['breach_detection','audit_logging']),

  -- Privacy Act AU
  ('privacy_act_au','APP 11','Security of Personal Information','Organisations must take reasonable steps to protect personal information from misuse, interference, loss, and unauthorised access, modification, or disclosure.','DLP implements APP 11''s reasonable steps requirement by controlling access to and transmission of personal information across all channels.','AUD 50M or 30% of adjusted turnover','critical',ARRAY['data_classification','dlp_web','dlp_email','dlp_endpoint','encryption_transit','access_controls']),
  ('privacy_act_au','NDB Scheme (s26WH)','Notifiable Data Breach Reporting','Eligible data breaches must be reported to the OAIC and affected individuals as soon as practicable.','DLP breach detection is the triggering mechanism for the NDB scheme — it identifies eligible data breaches and provides scope information for notification.','AUD 50M or 30% of adjusted turnover','critical',ARRAY['breach_detection','audit_logging']),

  -- PIPA (KR)
  ('pipa_kr','Article 29','Safety Measures for Personal Information','Personal information controllers must implement technical, managerial, and physical measures to prevent loss, theft, leakage, alteration, or damage.','DLP technical measures directly satisfy PIPA''s safety measure requirements for preventing personal information leakage.','3% of annual revenue','critical',ARRAY['data_classification','dlp_web','dlp_email','dlp_endpoint','encryption_transit']),
  ('pipa_kr','Article 34','Notification of Data Breach','Controllers must notify affected data subjects and report to the PIPC without undue delay in the event of a data breach.','DLP breach detection enables prompt identification and scoping of data breaches for PIPA notification requirements.','KRW 100M criminal fine','high',ARRAY['breach_detection','audit_logging']),

  -- PDPL (SA)
  ('pdpl_sa','Article 19','Security and Confidentiality','Controllers must implement adequate technical and organisational measures to protect personal data from breach, damage, unauthorised access, and illegal use.','DLP technical measures directly implement the security and confidentiality obligation under PDPL for personal data protection.','SAR 5M per violation','critical',ARRAY['data_classification','dlp_web','dlp_email','dlp_endpoint','encryption_transit','access_controls']),
  ('pdpl_sa','Article 28','Data Breach Notification (72-hour)','Controllers must notify the NDMO within 72 hours and affected data subjects without undue delay in the event of a personal data breach.','DLP breach detection provides the capability needed to identify breaches and meet the PDPL''s 72-hour notification requirement.','SAR 5M per violation','critical',ARRAY['breach_detection','audit_logging']),
  ('pdpl_sa','Article 29','Cross-Border Data Transfer','Transfer of personal data outside Saudi Arabia requires a legitimate basis and must not harm national interests or the interests of data subjects.','DLP controls on web uploads, email, and cloud applications are essential for monitoring and controlling cross-border data transfers under PDPL.','SAR 5M per violation','high',ARRAY['dlp_web','dlp_email','dlp_saas','data_classification']),

  -- POPIA
  ('popia','Section 19','Security Measures','Responsible parties must secure the integrity and confidentiality of personal information by taking appropriate, reasonable technical and organisational measures.','DLP technical measures implement the POPIA security obligation for protecting personal information across all channels.','ZAR 10M per violation','critical',ARRAY['data_classification','dlp_web','dlp_email','dlp_endpoint','encryption_transit','access_controls']),
  ('popia','Section 22','Notification of Security Compromises','Where there are reasonable grounds to believe personal information has been accessed by an unauthorised person, the responsible party must notify the Regulator and the data subject.','DLP breach detection enables identification of security compromises for POPIA notification obligations.','ZAR 10M per violation','high',ARRAY['breach_detection','audit_logging']),

  -- PIPEDA
  ('pipeda','Principle 7 (Schedule 1)','Safeguards','Personal information must be protected by security safeguards appropriate to the sensitivity of the information, including protection against unauthorised access, disclosure, copying, use or modification.','DLP implements PIPEDA''s safeguards principle, particularly for protecting sensitive personal information from unauthorised access and disclosure.','CAD 100,000 (current); CAD 25M under Bill C-27','critical',ARRAY['data_classification','dlp_web','dlp_email','dlp_endpoint','encryption_transit']),
  ('pipeda','Breach Regulations §3','Mandatory Breach Reporting','Organisations must report breaches posing a real risk of significant harm to the Privacy Commissioner and notify affected individuals as soon as feasible.','DLP breach detection enables identification of breaches posing real risk of significant harm for PIPEDA reporting obligations.','CAD 100,000 per violation','high',ARRAY['breach_detection','audit_logging']),

  -- LGPD
  ('lgpd','Article 46','Security Measures','Controllers and processors must adopt security, technical, and administrative measures capable of protecting personal data from unauthorised access and accidental or unlawful situations of destruction, loss, alteration, communication, or any form of improper or unlawful treatment.','DLP is a primary technical measure under LGPD for protecting personal data from unauthorised access and exfiltration.','2% of Brazil revenue, max BRL 50M','critical',ARRAY['data_classification','dlp_web','dlp_email','dlp_endpoint','encryption_transit','access_controls']),
  ('lgpd','Article 48','Incident Notification','Controllers must notify the ANPD and affected data subjects of security incidents that may create risk or relevant harm (typically within 2 business days under ANPD guidance).','DLP breach detection enables identification of security incidents for LGPD notification obligations.','2% of Brazil revenue, max BRL 50M','high',ARRAY['breach_detection','audit_logging'])

